using System.Collections.Concurrent;

namespace sv_83a4d5959f974f5f863c2df9949852c4.Services;

public class WizardData
{
    // Step 1: Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    // Track completed steps
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

/// <summary>
/// Singleton store that holds wizard data keyed by session ID.
/// Both static SSR (layout) and interactive server (pages) access this
/// using the same session cookie value.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new WizardData());
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Http;

namespace sv_83a4d5959f974f5f863c2df9949852c4.Services;

/// <summary>
/// Provides the wizard session ID from the HTTP cookie.
/// Works in both static SSR and interactive server contexts by reading
/// the cookie during the initial HTTP request (available via IHttpContextAccessor).
/// </summary>
public class WizardSessionProvider
{
    public const string CookieName = "WizardSessionId";

    private readonly IHttpContextAccessor _httpContextAccessor;

    public WizardSessionProvider(IHttpContextAccessor httpContextAccessor)
    {
        _httpContextAccessor = httpContextAccessor;
    }

    public string GetSessionId()
    {
        var context = _httpContextAccessor.HttpContext;
        if (context is null)
            return string.Empty;

        if (context.Request.Cookies.TryGetValue(CookieName, out var sessionId) &&
            !string.IsNullOrEmpty(sessionId))
        {
            return sessionId;
        }

        // Generate a new session ID and set the cookie
        sessionId = Guid.NewGuid().ToString("N");
        context.Response.Cookies.Append(CookieName, sessionId, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            MaxAge = TimeSpan.FromHours(24)
        });

        return sessionId;
    }
}

