@inject sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardStateStore Store
@inject sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardSessionProvider SessionProvider
@inject NavigationManager Nav

@{
    var sessionId = SessionProvider.GetSessionId();
    var data = Store.GetOrCreate(sessionId);
    var currentStep = GetCurrentStep();
}

<div class="container py-4">
    <h2 class="mb-3">Job Application</h2>

    <nav class="mb-4">
        <div class="d-flex gap-2 align-items-center">
            @for (int i = 1; i <= Steps.Length; i++)
            {
                var step = i;
                var isCurrent = step == currentStep;
                var isCompleted = data.CompletedSteps.Contains(step);
                var badgeClass = isCurrent ? "badge bg-primary" :
                                 isCompleted ? "badge bg-success" :
                                 "badge bg-secondary";

                <a href="@Steps[step - 1].Url" class="text-decoration-none">
                    <span class="@badgeClass p-2">
                        @step. @Steps[step - 1].Label
                        @if (isCompleted) { <text>✓</text> }
                    </span>
                </a>

                @if (step < Steps.Length)
                {
                    <span class="text-muted">→</span>
                }
            }
        </div>
        <div class="progress mt-2" style="height: 6px;">
            <div class="progress-bar" style="width: @((currentStep) * 100 / Steps.Length)%"></div>
        </div>
        <small class="text-muted">Step @currentStep of @Steps.Length</small>
    </nav>

    <div class="card">
        <div class="card-body">
            @Body
        </div>
    </div>
</div>

@code {
    private record StepInfo(string Url, string Label);

    private static readonly StepInfo[] Steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review")
    ];

    private int GetCurrentStep()
    {
        var uri = Nav.ToBaseRelativePath(Nav.Uri).ToLowerInvariant();
        for (int i = 0; i < Steps.Length; i++)
        {
            if (uri.Contains(Steps[i].Url.TrimStart('/').ToLowerInvariant()))
                return i + 1;
        }
        return 1;
    }
}

@page "/apply/personal-info"
@layout WizardLayout
@rendermode InteractiveServer

@inject sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardStateStore Store
@inject sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardSessionProvider SessionProvider
@inject NavigationManager Nav

<h3>Personal Information</h3>

<EditForm Model="this" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="_email" type="email" />
    </div>
    <div class="d-flex justify-content-end">
        <button type="submit" class="btn btn-primary">Next →</button>
    </div>
</EditForm>

@code {
    private string _name = string.Empty;
    private string _email = string.Empty;
    private string _sessionId = string.Empty;

    protected override void OnInitialized()
    {
        _sessionId = SessionProvider.GetSessionId();
        var data = Store.GetOrCreate(_sessionId);
        _name = data.Name;
        _email = data.Email;
    }

    private void Next()
    {
        var data = Store.GetOrCreate(_sessionId);
        data.Name = _name;
        data.Email = _email;
        data.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@layout WizardLayout
@rendermode InteractiveServer

@inject sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardStateStore Store
@inject sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardSessionProvider SessionProvider
@inject NavigationManager Nav

<h3>Work Experience</h3>

@if (_jobs.Count == 0)
{
    <p class="text-muted">No job history added yet. Click "Add Job" to begin.</p>
}

@for (int i = 0; i < _jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3">
        <div class="card-body">
            <div class="row g-2">
                <div class="col-md-4">
                    <label class="form-label">Company</label>
                    <input class="form-control" @bind="_jobs[index].Company" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Job Title</label>
                    <input class="form-control" @bind="_jobs[index].Title" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Years</label>
                    <input class="form-control" @bind="_jobs[index].Years" />
                </div>
                <div class="col-md-1 d-flex align-items-end">
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveJob(index)">✕</button>
                </div>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private List<sv_83a4d5959f974f5f863c2df9949852c4.Services.JobEntry> _jobs = [];
    private string _sessionId = string.Empty;

    protected override void OnInitialized()
    {
        _sessionId = SessionProvider.GetSessionId();
        var data = Store.GetOrCreate(_sessionId);
        // Clone list so edits are local until saved
        _jobs = data.JobHistory.Select(j => new Services.JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();
    }

    private void AddJob() => _jobs.Add(new());
    private void RemoveJob(int index) => _jobs.RemoveAt(index);

    private void Save()
    {
        var data = Store.GetOrCreate(_sessionId);
        data.JobHistory = _jobs;
        data.CompletedSteps.Add(2);
    }

    private void Next() { Save(); Nav.NavigateTo("/apply/references"); }
    private void Back() { Save(); Nav.NavigateTo("/apply/personal-info"); }
}

