@layout WizardLayout
@rendermode InteractiveServer

@inject sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardStateStore Store
@inject sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardSessionProvider SessionProvider
@inject NavigationManager Nav

<h3>Review Your Application</h3>

@if (_data is not null)
{
    <div class="mb-4">
        <h5>Personal Information</h5>
        <dl class="row">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@_data.Name</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@_data.Email</dd>
        </dl>
    </div>

    <div class="mb-4">
        <h5>Work Experience</h5>
        @if (_data.JobHistory.Count == 0)
        {
            <p class="text-muted">None provided.</p>
        }
        else
        {
            <table class="table table-sm">
                <thead><tr><th>Company</th><th>Title</th><th>Years</th></tr></thead>
                <tbody>
                    @foreach (var job in _data.JobHistory)
                    {
                        <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Years</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>

    <div class="mb-4">
        <h5>References</h5>
        @if (_data.References.Count == 0)
        {
            <p class="text-muted">None provided.</p>
        }
        else
        {
            <table class="table table-sm">
                <thead><tr><th>Name</th><th>Email</th><th>Relationship</th></tr></thead>
                <tbody>
                    @foreach (var r in _data.References)
                    {
                        <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="Back">← Back</button>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">Your application has been submitted!</div>
    }
}

@code {
    private sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardData? _data;
    private string _sessionId = string.Empty;
    private bool _submitted;

    protected override void OnInitialized()
    {
        _sessionId = SessionProvider.GetSessionId();
        _data = Store.GetOrCreate(_sessionId);
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        _data!.CompletedSteps.Add(4);
        _submitted = true;
    }
}
