@page "/apply/experience"
@layout WizardLayout
@rendermode InteractiveServer

@inject sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardStateStore Store
@inject sv_83a4d5959f974f5f863c2df9949852c4.Services.WizardSessionProvider SessionProvider
@inject NavigationManager Nav

<h3>Work Experience</h3>

@if (_jobs.Count == 0)
{
    <p class="text-muted">No job history added yet. Click "Add Job" to begin.</p>
}

@for (int i = 0; i < _jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3">
        <div class="card-body">
            <div class="row g-2">
                <div class="col-md-4">
                    <label class="form-label">Company</label>
                    <input class="form-control" @bind="_jobs[index].Company" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Job Title</label>
                    <input class="form-control" @bind="_jobs[index].Title" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Years</label>
                    <input class="form-control" @bind="_jobs[index].Years" />
                </div>
                <div class="col-md-1 d-flex align-items-end">
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveJob(index)">✕</button>
                </div>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private List<sv_83a4d5959f974f5f863c2df9949852c4.Services.JobEntry> _jobs = [];
    private string _sessionId = string.Empty;

    protected override void OnInitialized()
    {
        _sessionId = SessionProvider.GetSessionId();
        var data = Store.GetOrCreate(_sessionId);
        // Clone list so edits are local until saved
        _jobs = data.JobHistory.Select(j => new Services.JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();
    }

    private void AddJob() => _jobs.Add(new());
    private void RemoveJob(int index) => _jobs.RemoveAt(index);

    private void Save()
    {
        var data = Store.GetOrCreate(_sessionId);
        data.JobHistory = _jobs;
        data.CompletedSteps.Add(2);
    }

    private void Next() { Save(); Nav.NavigateTo("/apply/references"); }
    private void Back() { Save(); Nav.NavigateTo("/apply/personal-info"); }
}

